steps.script:
var u = GameState.state["units"]["U_BOYZ_FL"]
var meta = u.get("meta", {})
var abilities = meta.get("abilities", [])
abilities.append({"name": "Moment Shackle"})
meta["abilities"] = abilities
u["meta"] = meta
if not u.has("flags"):
	u["flags"] = {}
u["flags"]["moment_shackle_used"] = false
var fp = PhaseManager.get_current_phase_instance()
fp._moment_shackle_pending_units = ["U_BOYZ_FL"]
fp._maybe_offer_moment_shackle()
return true

var d = tree.root.get_node_or_null("MomentShackleDialog")
if d == null:
	return "NO_DIALOG"
var btns = d.find_children("*", "Button", true, false)
var has_attacks = false
var has_decline = false
for b in btns:
	var t = String(b.text)
	if t.contains("12 Attacks"):
		has_attacks = true
	if t.contains("Decline"):
		has_decline = true
return has_attacks and has_decline

var d = tree.root.get_node_or_null("MomentShackleDialog")
if d == null:
	return "NO_DIALOG"
d._on_attacks_pressed()
return true
